static Uint32 CommMaintAddrConcatU32(Uint8 *vp_buff_u8, Uint16 v_baseIdx_u16, Uint16 v_byteNum_u16)
{
    Uint32 l_addr_u32 = 0UL;       /* 拼接结果地址 */
    Uint16 l_ii_u16 = 0U;          /* 循环索引 */

    /* 从最高字节开始，逐字节左移拼接 */
    for(l_ii_u16 = 0U; l_ii_u16 < v_byteNum_u16; l_ii_u16++)
    {
        l_addr_u32 = l_addr_u32 << 8U;
        l_addr_u32 = l_addr_u32 + (Uint32)(vp_buff_u8[v_baseIdx_u16 - l_ii_u16] & 0xFFU);
    }

    return l_addr_u32;
}

static void MaintCommInfoProcess(Uint16 v_commID_u16,Uint16 v_sIndex_u16)
{
