    s_kzzzTxCache_t.lastRpPreFuel_u16 = 0xFFFFU;
    s_bitEventLastVal_u16[0U][0U] = 0xFFFFU;
    s_bitEventLastVal_u16[0U][1U] = 0xFFFFU;
    s_bitEventLastVal_u16[1U][0U] = 0xFFFFU;
    s_bitEventLastVal_u16[1U][1U] = 0xFFFFU;
