static Uint16 RIUOrigBitGet(const Orig429Data_t *vp_orig_t, Uint16 v_shift_u16)
{
    union arinc429Data l_rdata_un;
    l_rdata_un.msgData = 0UL;
    if(NULL != vp_orig_t)
    {
        l_rdata_un.msgData = vp_orig_t->OrigData_u32;
    }
    return (Uint16)((l_rdata_un.bit.data >> v_shift_u16) & 0x1UL);
}

static Uint16 RIUOrigBitsGet(const Orig429Data_t *vp_orig_t, Uint16 v_shift_u16, Uint16 v_mask_u16)
{
    union arinc429Data l_rdata_un;
    l_rdata_un.msgData = 0UL;
    if(NULL != vp_orig_t)
    {
        l_rdata_un.msgData = vp_orig_t->OrigData_u32;
    }
    return (Uint16)((l_rdata_un.bit.data >> v_shift_u16) & (Uint32)v_mask_u16);
}

void Comm429KZZZPeriodInfoTx(void)
{
    RIU429InfoData_t l_RIU429RxData_t;
    RIU429OrigData_t l_RIU429OrigData_t;
    Uint16 l_commID_u16 = COMM429_RIU_1;
    Uint16 l_riuValid_u16 = INVALID;
    Uint16 l_mbitCmd_u16 = 0U;
    Uint16 l_pzValid_u16 = 0U;
    Uint16 l_lowFuel_u16 = 0U;
    Uint16 l_air_u16 = 0U;
    Uint16 l_fuelReset_u16 = 0U;
    Uint16 l_eventIdx_u16 = 0U;
    Uint16 l_side_u16 = 0U;
    Uint16 l_kzzzID_u16 = 0U;
    Uint16 l_bitVal_u16 = 0U;
    Uint16 l_preFuelQuant_u16 = 0U;

    /* 控制输出未授权时直接复位发送缓存并返回，避免下一拍拿到陈旧事件沿 */
    if (CON_OUT_STATE_VALID != s_sysConData_t.ConOutData_t.conOutState_u16)
    {
        KZZZTxCacheReset();
        return;
    }

    /* RIU数据先零初始化，确保未取到源时所有派生字段(密度/预选油量/控制字)为0 */
    memset(&l_RIU429RxData_t, 0, sizeof(l_RIU429RxData_t));
    memset(&l_RIU429OrigData_t, 0, sizeof(l_RIU429OrigData_t));

    /* 按控制链统一口径挑选当前有效RIU源，未命中时数据保持0 */
    ControlRIUActiveSourceSelect(&l_commID_u16, &l_riuValid_u16);
    if (VALID == l_riuValid_u16)
    {
        l_RIU429RxData_t = Comm429RIURxDataGet(l_commID_u16);
        l_RIU429OrigData_t = Comm429RIUOrigDataGet(l_commID_u16);
    }
    /* 调试心跳:无条件把当前时间发给左右吊舱，不依赖对端请求位 */
    /* RIU在线时秒字段随真实时间跳变，离线时发送0，KZZZ物理层始终有帧 */
    Comm429KZZZCurrTimeTx(COMM429_KZZZ_1, l_RIU429RxData_t);
    Comm429KZZZCurrTimeTx(COMM429_KZZZ_2, l_RIU429RxData_t);

    /* MBIT执行命令来自RIU原始字MBIT_EXE字段(bit0-bit1,2位宽) */
    /* 仅在命令值边沿变化时重发，非零才下发，0代表无新命令 */
    l_mbitCmd_u16 = RIUOrigBitsGet(&l_RIU429OrigData_t.Orig_Rx_t[RIU_R_DATA_INDEX_MBIT_EXEC], 0U, 0x3U);
    if (s_kzzzTxCache_t.lastMbitCmd_u16 != l_mbitCmd_u16)
    {
        s_kzzzTxCache_t.lastMbitCmd_u16 = l_mbitCmd_u16;
        if (0U != l_mbitCmd_u16)
        {
            Comm429KZZZSendDual(KZZZ_LABEL_T_MBIT_RUN, (Uint32)(l_mbitCmd_u16 & 0x3U));
        }
    }

    /* PZ信息有效位来自RIU软件版本请求字，由RIU触发吊舱进入配置模式 */
    /* 下降沿不撤除，仅上升沿触发一次性的PZXX下发 */
    l_pzValid_u16 = RIUOrigBitGet(&l_RIU429OrigData_t.Orig_Rx_t[RIU_R_DATA_INDEX_SOFTV_REQ], 0U);
    if (s_kzzzTxCache_t.lastPzValid_u16 != l_pzValid_u16)
    {
        s_kzzzTxCache_t.lastPzValid_u16 = l_pzValid_u16;
        if (VALID == l_pzValid_u16)
        {
            Comm429KZZZSendDual(KZZZ_LABEL_T_PZXX, (Uint32)(l_pzValid_u16 & 0x1U));
        }
    }

    /* 左吊舱预选油量:浮点除以油量比得到整数化量子，仅在变化时下发 */
    l_preFuelQuant_u16 = (Uint16)(l_RIU429RxData_t.lpPFV_f / OIL_RATIO);
    if (s_kzzzTxCache_t.lastLpPreFuel_u16 != l_preFuelQuant_u16)
    {
        s_kzzzTxCache_t.lastLpPreFuel_u16 = l_preFuelQuant_u16;
        Comm429KZZZSendPreFuel(COMM429_KZZZ_1, l_RIU429RxData_t.lpPFV_f);
    }
    /* 右吊舱预选油量同上，独立缓存避免左右交叉污染 */
    l_preFuelQuant_u16 = (Uint16)(l_RIU429RxData_t.rpPFV_f / OIL_RATIO);
    if (s_kzzzTxCache_t.lastRpPreFuel_u16 != l_preFuelQuant_u16)
    {
        s_kzzzTxCache_t.lastRpPreFuel_u16 = l_preFuelQuant_u16;
        Comm429KZZZSendPreFuel(COMM429_KZZZ_2, l_RIU429RxData_t.rpPFV_f);
    }

    /* KZZZ事件量扫描:每拍轮询所有事件源(寿命/油量复位)和左右吊舱 */
    /* 任一位由0变1时一次性下发对应事件帧，再变回0不主动撤除 */
    for (l_eventIdx_u16 = 0U; l_eventIdx_u16 < KZZZ_BIT_EVENT_NUM; l_eventIdx_u16++)
    {
        for (l_side_u16 = 0U; l_side_u16 < COMM429_KZZZ_NUM; l_side_u16++)
        {
            l_kzzzID_u16 = s_sideToKzzz_u16[l_side_u16];
            /* 从RIU原始字按事件索引表取出对应位的请求状态 */
            l_bitVal_u16 = RIUOrigBitGet(
                &l_RIU429OrigData_t.Orig_Rx_t[s_bitEventRiuIdx_u16[l_eventIdx_u16]],
                l_side_u16);

            /* 边沿检测:仅在状态变化时考虑下发 */
            if (l_bitVal_u16 != s_bitEventLastVal_u16[l_eventIdx_u16][l_side_u16])
            {
                s_bitEventLastVal_u16[l_eventIdx_u16][l_side_u16] = l_bitVal_u16;
                if (VALID == l_bitVal_u16)
                {
                    /* 索引0映射到寿命信息，索引1映射到油量复位 */
                    if (0U == l_eventIdx_u16)
                    {
                        Comm429KZZZSendLifeInfo(l_kzzzID_u16, l_bitVal_u16);
                    }
                    else
                    {
                        Comm429KZZZSendOilReset(l_kzzzID_u16, l_bitVal_u16);
                    }
                }
            }
        }
    }

    /* 周期性慢速帧分频:每4拍(200ms)发一次燃油密度和控制字，避免429总线过载 */
    s_kzzzTxCache_t.periodicDiv_u16 = (Uint16)((s_kzzzTxCache_t.periodicDiv_u16 + 1U) % KZZZ_PERIODIC_SEND_DIV);
    if (0U == s_kzzzTxCache_t.periodicDiv_u16)
    {
        /* 燃油密度每200ms双发，RIU离线时发0.0 */
        Comm429KZZZSendFuelDensity(l_RIU429RxData_t.oilMD_f);
        /* 低油量信号取自RIU控制字bit9 */
        l_lowFuel_u16 = (Uint16)((l_RIU429RxData_t.ctrlCmd_u16 >> 9U) & 0x1U);
        /* 空地标志由RIU轮载状态判读，仅地态(RIU_DK_AIR)置1 */
        if (RIU_DK_AIR == l_RIU429RxData_t.wheelLoad_u16)
        {
            l_air_u16 = 1U;
        }
        else
        {
            l_air_u16 = 0U;
        }
        /* 油量重置信号取自RIU控制字bit10 */
        l_fuelReset_u16 = (Uint16)((l_RIU429RxData_t.ctrlCmd_u16 >> 10U) & 0x1U);
        /* 控制字三合一(低油量/空地/油量重置)双发 */
        Comm429KZZZSendCtrlCmd(l_lowFuel_u16, l_air_u16, l_fuelReset_u16);
    }
}

