    static Uint16 l_s_heartPhase_u16[COMM429_RIU_NUM];  /* 心跳相位，0/1交替 */
    Uint32 l_tData_u32 = 0UL;  /* 临时数据 */
    Uint16 l_valid_u16 = INVALID;

    /* 输入ID号小于ID数量 */
    if( v_ID_u16 < COMM429_RIU_NUM )
