        }

        if(VALID == l_rightPreFuelReqChanged_u16)
        {
            Comm429RIUPodEventInfoTx(l_ID_u16, COMM429_KZZZ_2, RIU_POD_EVENT_GROUP_PRE_FUEL, l_rightValid_u16, l_rightData_t);
