        }

        if(VALID == l_lifeReqChanged_u16)
        {
            if(0U != l_lifeLeftReq_u16)
            {
                Comm429RIUPodEventInfoTx(l_ID_u16, COMM429_KZZZ_1, RIU_POD_EVENT_GROUP_LIFE, l_leftValid_u16, l_leftData_t);
