void StateCondInjectApplySubcmd(Uint16 v_subcmd_u16, const Uint16 *vp_payload_u16)
{
    /* 解析 EN/DISABLE 之外的子命令,需先在注入使能窗口内才生效 */
    Uint16 l_timeoutSec_u16 = 0U;

    /* 载荷指针为空直接退出 */
    if (NULL == vp_payload_u16)
    {
        return;
    }

    /* 子命令 = 关闭:关闭注入并返回 */
    if (STATE_COND_SUBCMD_DISABLE == v_subcmd_u16)
    {
        StateCondInjectDisable();
        return;
    }

    /* 子命令 = 开启:解析超时并建立注入窗口 */
    if (STATE_COND_SUBCMD_ENABLE == v_subcmd_u16)
    {
        l_timeoutSec_u16 = vp_payload_u16[0] & 0xFFU;
        /* 超时为0则用默认值 */
        if (0U == l_timeoutSec_u16)
        {
            l_timeoutSec_u16 = (Uint16)(STATE_COND_DEFAULT_TIMEOUT_MS / 1000UL);
        }
        /* 超时超过上限则截到上限 */
        if (l_timeoutSec_u16 > STATE_COND_MAX_TIMEOUT_SEC)
        {
            l_timeoutSec_u16 = STATE_COND_MAX_TIMEOUT_SEC;
        }
    /* 写入使能位、子命令记录与到期时间 */
        s_stateCondActive_u16 = VALID;
        s_stateCondLastSubcmd_u16 = STATE_COND_SUBCMD_ENABLE;
        s_stateCondExpireTime_u32 = sysTime() + (((Uint32)l_timeoutSec_u16) * 1000UL);
        return;
    }

    /* 其他子命令必须先确认注入处于活跃状态 */
    if (VALID != StateCondInjectActiveNow())
    {
        return;
    }

    /* 刷新子命令记录与默认超时(供后续子命令使用) */
    s_stateCondLastSubcmd_u16 = v_subcmd_u16;
    s_stateCondExpireTime_u32 = sysTime() + STATE_COND_DEFAULT_TIMEOUT_MS;

    /* 按子命令写入对应的注入载荷 */
    switch (v_subcmd_u16)
    {
        /* IO 注入:采集掩码/维护IO/28V电源IO */
        case STATE_COND_SUBCMD_IO:
            s_stateCondIoMask_u16 = vp_payload_u16[0] & 0x03U;
            s_stateCondMaintIo_u16 = vp_payload_u16[1] & 0xFFU;
            s_stateCondPower28vIo_u16 = vp_payload_u16[2] & 0xFFU;
            break;

        /* BIT 注入:BIT掩码/PUBIT关键故障/IFBIT与MBIT故障等级 */
        case STATE_COND_SUBCMD_BIT:
            s_stateCondBitMask_u16 = vp_payload_u16[0] & 0x07U;
            s_stateCondPuBitKeyFault_u16 = vp_payload_u16[1] & 0x01U;
            s_stateCondIFBitLevel_u16 = vp_payload_u16[2] & 0x07U;
            s_stateCondMBitLevel_u16 = vp_payload_u16[3] & 0x07U;
            break;

        /* 未知子命令:不做处理 */
        default:
            break;
    }
}

StateCondInjectStatus_t StateCondInjectStatusGet(void)
{
    StateCondInjectStatus_t l_status_t;
    Uint32 l_now_u32 = sysTime();
    memset(&l_status_t, 0, sizeof(l_status_t));

    l_status_t.active_u16 = StateCondInjectActiveNow();
    l_status_t.lastSubcmd_u16 = s_stateCondLastSubcmd_u16;
    if ((VALID == l_status_t.active_u16) && (s_stateCondExpireTime_u32 > l_now_u32))
    {
        l_status_t.timeoutRemain_u16 = (Uint16)((s_stateCondExpireTime_u32 - l_now_u32) / 100UL);
    }
    l_status_t.ioMask_u16 = s_stateCondIoMask_u16;
    l_status_t.maintIo_u16 = s_stateCondMaintIo_u16;
    l_status_t.power28vIo_u16 = s_stateCondPower28vIo_u16;
    l_status_t.bitMask_u16 = s_stateCondBitMask_u16;
    l_status_t.puBitKeyFault_u16 = s_stateCondPuBitKeyFault_u16;
    l_status_t.ifBitLevel_u16 = s_stateCondIFBitLevel_u16;
    l_status_t.mBitLevel_u16 = s_stateCondMBitLevel_u16;

    return l_status_t;
}

Uint16 StateCondIoOverrideGet(Uint16 v_index_u16, Uint16 *vp_value_u16)
{
    Uint16 l_valid_u16 = INVALID;

    if ((NULL != vp_value_u16) && (VALID == StateCondInjectActiveNow()))
    {
        if ((IO_DINDEX_MAINTANCE == v_index_u16) && (0U != (s_stateCondIoMask_u16 & 0x01U)))
        {
            *vp_value_u16 = s_stateCondMaintIo_u16;
            l_valid_u16 = VALID;
        }
        else if ((IO_DINDEX_POWER_28V == v_index_u16) && (0U != (s_stateCondIoMask_u16 & 0x02U)))
        {
            *vp_value_u16 = s_stateCondPower28vIo_u16;
            l_valid_u16 = VALID;
        }
    }

    return l_valid_u16;
}

Uint16 StateCondPuBitOverrideGet(Uint16 *vp_keyFault_u16)
{
    if ((NULL != vp_keyFault_u16) &&
        (VALID == StateCondInjectActiveNow()) &&
        (0U != (s_stateCondBitMask_u16 & 0x01U)))
    {
        *vp_keyFault_u16 = s_stateCondPuBitKeyFault_u16;
        return VALID;
    }
    return INVALID;
}

Uint16 StateCondIFBitLevelOverrideGet(Uint16 *vp_level_u16)
{
    if ((NULL != vp_level_u16) &&
        (VALID == StateCondInjectActiveNow()) &&
        (0U != (s_stateCondBitMask_u16 & 0x02U)))
    {
        *vp_level_u16 = s_stateCondIFBitLevel_u16;
        return VALID;
    }
    return INVALID;
}

Uint16 StateCondMBitLevelOverrideGet(Uint16 *vp_level_u16)
{
    if ((NULL != vp_level_u16) &&
        (VALID == StateCondInjectActiveNow()) &&
        (0U != (s_stateCondBitMask_u16 & 0x04U)))
    {
        *vp_level_u16 = s_stateCondMBitLevel_u16;
        return VALID;
    }
    return INVALID;
}

